/* Sai Ram Labs design tokens — cosmic+bookish baseline. Lifted from spiritual-reader v1.1. */

/* === FONTS ================================================================ */
@import url('https://fonts.googleapis.com/css2?family=Fraunces:ital,opsz,wght@0,9..144,300;0,9..144,400;0,9..144,600;1,9..144,300;1,9..144,400;1,9..144,600&family=JetBrains+Mono:wght@400&display=swap');

:root {
  /* === COLOR ============================================================== */
  --bg:              #0B0D1A;
  --surface:         #111328;
  --surface-raised:  #181B35;
  --fg:              #EDE9DF;
  --fg-muted:        #8A8BA8;
  --fg-dim:          #55576E;
  --accent:          #B8A8E8;
  --accent-warm:     #C9A96E;
  --border:          #1F2244;
  --border-strong:   #2D3060;
  --danger:          #D95E5E;
  --warn:            #C9973A;
  --ok:              #5A9E7B;

  /* === RADIUS ============================================================= */
  --r-sm:  4px;
  --r-md:  8px;
  --r-lg:  16px;
  --r-xl:  24px;

  /* === SHADOW / ELEVATION ================================================= */
  --shadow-sm:  0 1px 3px rgba(0, 0, 0, 0.4);
  --shadow-md:  0 4px 16px rgba(0, 0, 0, 0.5);
  --shadow-lg:  0 12px 40px rgba(0, 0, 0, 0.6);

  /* === OPACITY ============================================================ */
  --opacity-disabled:  0.38;
  --opacity-overlay:   0.72;
  --opacity-subtle:    0.08;

  /* === SPACING ============================================================ */
  --sp-1:  4px;
  --sp-2:  8px;
  --sp-3:  12px;
  --sp-4:  16px;
  --sp-6:  24px;
  --sp-8:  32px;
  --sp-12: 48px;
  --sp-16: 64px;
  --sp-24: 96px;

  /* === TYPOGRAPHY ========================================================= */
  --font-primary: 'Fraunces', Georgia, serif;
  --font-mono:    'JetBrains Mono', 'Courier New', monospace;

  --text-h1:    2rem;
  --text-h2:    1.5rem;
  --text-h3:    1.125rem;
  --text-body:  1rem;
  --text-small: 0.875rem;
  --text-xs:    0.75rem;

  --lh-h1:    1.2;
  --lh-h2:    1.3;
  --lh-h3:    1.4;
  --lh-body:  1.75;
  --lh-small: 1.6;
  --lh-xs:    1.5;

  /* === MOTION ============================================================= */
  --duration-fast:   120ms;
  --duration-base:   200ms;
  --duration-slow:   320ms;

  --ease-standard:   cubic-bezier(0.2, 0, 0, 1);
  --ease-decelerate: cubic-bezier(0, 0, 0.2, 1);
  --ease-accelerate: cubic-bezier(0.4, 0, 1, 1);
}

/* === REDUCED MOTION ====================================================== */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    transition-duration: 0.01ms !important;
  }
}

/* === BASE ================================================================ */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html, body, #root {
  height: 100%;
}

body {
  font-family: var(--font-primary);
  font-size: var(--text-body);
  line-height: var(--lh-body);
  color: var(--fg);
  background-color: var(--bg);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  font-variation-settings: 'opsz' 14;
}

h1, h2, h3 {
  font-variation-settings: 'opsz' 20;
}

/* Pulse dot animation for StatusBadge */
@keyframes pulse-dot {
  0%, 100% { opacity: 1; transform: scale(1); }
  50%       { opacity: 0.5; transform: scale(0.8); }
}

/* Focus ring */
:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}
